/*!
 * signature_pad.min.js — minimal, API-compatible signature pad.
 *
 * The upstream SignaturePad (https://github.com/szimek/signature_pad, MIT) could
 * not be vendored from the CDN in this environment (egress policy blocks
 * cdnjs.cloudflare.com). This is a small drop-in that implements the exact
 * surface RentalOS uses: `new SignaturePad(canvas, { backgroundColor, penColor })`,
 * `.clear()`, `.isEmpty()`, and `.toDataURL(type)`. Pointer + touch + mouse input,
 * HiDPI-safe (the caller scales the 2D context; drawing uses CSS-pixel coords).
 * Swap in the upstream library verbatim if/when the CDN is reachable.
 */
(function (global) {
  'use strict';

  function SignaturePad(canvas, options) {
    options = options || {};
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d');
    this.backgroundColor = options.backgroundColor || 'rgba(0,0,0,0)';
    this.penColor = options.penColor || 'black';
    this.minWidth = options.minWidth || 1.2;
    this.maxWidth = options.maxWidth || 2.6;
    this._empty = true;
    this._drawing = false;
    this._last = null;
    this._fillBackground();
    this._bind();
  }

  SignaturePad.prototype._fillBackground = function () {
    var ctx = this.ctx, c = this.canvas;
    ctx.save();
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    if (this.backgroundColor && this.backgroundColor !== 'rgba(0,0,0,0)') {
      ctx.fillStyle = this.backgroundColor;
      ctx.fillRect(0, 0, c.width, c.height);
    } else {
      ctx.clearRect(0, 0, c.width, c.height);
    }
    ctx.restore();
  };

  SignaturePad.prototype._point = function (ev) {
    var rect = this.canvas.getBoundingClientRect();
    var src = (ev.touches && ev.touches[0]) ? ev.touches[0] : ev;
    return { x: src.clientX - rect.left, y: src.clientY - rect.top };
  };

  SignaturePad.prototype._begin = function (ev) {
    ev.preventDefault();
    this._drawing = true;
    this._last = this._point(ev);
    // A dot for a tap.
    var ctx = this.ctx;
    ctx.beginPath();
    ctx.fillStyle = this.penColor;
    ctx.arc(this._last.x, this._last.y, this.minWidth, 0, Math.PI * 2);
    ctx.fill();
    this._empty = false;
  };

  SignaturePad.prototype._move = function (ev) {
    if (!this._drawing) return;
    ev.preventDefault();
    var p = this._point(ev);
    var ctx = this.ctx;
    ctx.strokeStyle = this.penColor;
    ctx.lineWidth = this.maxWidth;
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.moveTo(this._last.x, this._last.y);
    ctx.lineTo(p.x, p.y);
    ctx.stroke();
    this._last = p;
    this._empty = false;
  };

  SignaturePad.prototype._end = function () {
    this._drawing = false;
    this._last = null;
  };

  SignaturePad.prototype._bind = function () {
    var self = this;
    this._onDown = function (e) { self._begin(e); };
    this._onMove = function (e) { self._move(e); };
    this._onUp = function () { self._end(); };
    var c = this.canvas;
    if (window.PointerEvent) {
      c.addEventListener('pointerdown', this._onDown);
      c.addEventListener('pointermove', this._onMove);
      window.addEventListener('pointerup', this._onUp);
    } else {
      c.addEventListener('mousedown', this._onDown);
      c.addEventListener('mousemove', this._onMove);
      window.addEventListener('mouseup', this._onUp);
      c.addEventListener('touchstart', this._onDown, { passive: false });
      c.addEventListener('touchmove', this._onMove, { passive: false });
      window.addEventListener('touchend', this._onUp);
    }
    c.style.touchAction = 'none';
  };

  SignaturePad.prototype.off = function () {
    var c = this.canvas;
    c.removeEventListener('pointerdown', this._onDown);
    c.removeEventListener('pointermove', this._onMove);
    window.removeEventListener('pointerup', this._onUp);
    c.removeEventListener('mousedown', this._onDown);
    c.removeEventListener('mousemove', this._onMove);
    window.removeEventListener('mouseup', this._onUp);
    c.removeEventListener('touchstart', this._onDown);
    c.removeEventListener('touchmove', this._onMove);
    window.removeEventListener('touchend', this._onUp);
  };

  SignaturePad.prototype.clear = function () {
    this._fillBackground();
    this._empty = true;
    this._drawing = false;
    this._last = null;
  };

  SignaturePad.prototype.isEmpty = function () {
    return this._empty;
  };

  SignaturePad.prototype.toDataURL = function (type) {
    return this.canvas.toDataURL(type || 'image/png');
  };

  if (typeof module !== 'undefined' && module.exports) {
    module.exports = SignaturePad;
    module.exports.default = SignaturePad;
  } else {
    global.SignaturePad = SignaturePad;
  }
})(typeof window !== 'undefined' ? window : this);
